mapper.update:
update seckill_order
user_id = #{userId}, coupon_id = #{couponId}, order_number = #{orderNumber}, status = #{status}, create_time = #{createTime}, pay_time = #{payTime}
where id = #{id}

mapper.select:
select so.id, so.user_id as userId, so.coupon_id as couponId, so.order_number as orderNumber, so.status, so.create_time as createTime, so.pay_time as payTime, sc.name as couponName, sc.original_price as originalPrice, sc.seckill_price as seckillPrice, sc.start_time as startTime, sc.end_time as endTime from seckill_order so left join seckill_coupon sc on so.coupon_id = sc.id where so.user_id = #{userId}
and so.status = #{status}
order by so.create_time desc

mapper.update:
update seckill_order
set status = #{status}
where order_number = #{orderNumber}

mapper.select:
select so.id, so.user_id as userId, so.coupon_id as couponId, so.order_number as orderNumber, 
       so.status, so.create_time as createTime, so.pay_time as payTime,
       sc.name as couponName, sc.seckill_price as seckillPrice,
       sa.name as activityName
from seckill_order so
left join seckill_coupon sc on so.coupon_id = sc.id
left join seckill_activity sa on sc.activity_id = sa.id


        and (so.order_number like concat('%', #{search}, '%') or so.user_id like concat('%', #{search}, '%'))


        and so.status = #{status}


        and sc.activity_id = #{activityId}


        and so.create_time >= #{startTime}


        and so.create_time <= #{endTime}


order by so.create_time desc
limit #{offset}, #{pageSize}

